import{c as a,Q as t,j as r,m as s}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Database reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/database.md","filePath":"reference/database.md","lastUpdated":null}'),d={name:"reference/database.md"};function o(c,e,i,l,n,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="database-reference" tabindex="-1">Database reference <a class="header-anchor" href="#database-reference" aria-label="Permalink to &quot;Database reference&quot;">​</a></h1><p>Audience: developers and careful power users<br> Goal: describe the current SQLite storage model<br> Type: reference</p><p>The main library database is SQLite. Schema writes are handled by the project database layer, which configures WAL and a busy timeout and serializes writes per database path.</p><h2 id="current-schema-version" tabindex="-1">Current schema version <a class="header-anchor" href="#current-schema-version" aria-label="Permalink to &quot;Current schema version&quot;">​</a></h2><p>The current library schema version is <code>4</code>.</p><h2 id="core-tables" tabindex="-1">Core tables <a class="header-anchor" href="#core-tables" aria-label="Permalink to &quot;Core tables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Table</th><th>Purpose</th></tr></thead><tbody><tr><td><code>tracks</code></td><td>paths, tags, derived fields, metadata JSON, analysis flags</td></tr><tr><td><code>embeddings</code></td><td>vector embeddings keyed by track and embedding key</td></tr><tr><td><code>library_settings</code></td><td>small database-scoped settings</td></tr><tr><td><code>track_classifier_scores</code></td><td>promoted classifier scores by track and key</td></tr><tr><td><code>track_likes</code></td><td>user liked-track state</td></tr><tr><td><code>track_search_fts</code></td><td>full-text search support</td></tr></tbody></table><p>The <code>embeddings</code> table uses <code>(track_id, embedding_key)</code> as its primary key. Classifier scores are scoped by <code>(track_id, classifier)</code>.</p><h2 id="track-fields" tabindex="-1">Track fields <a class="header-anchor" href="#track-fields" aria-label="Permalink to &quot;Track fields&quot;">​</a></h2><p>Track rows include stored path, artist, title, album, BPM, musical key, energy, duration, analysis availability flags, and <code>metadata_json</code>.</p><p>Stored <code>metadata_json</code> must remain JSON-safe.</p><h2 id="what-not-to-edit-manually" tabindex="-1">What not to edit manually <a class="header-anchor" href="#what-not-to-edit-manually" aria-label="Permalink to &quot;What not to edit manually&quot;">​</a></h2><p>Avoid hand-editing embeddings, classifier scores, search FTS rows, and schema metadata. Use project commands or focused helper scripts so indexes and caches stay coherent.</p><h2 id="local-user-state" tabindex="-1">Local user state <a class="header-anchor" href="#local-user-state" aria-label="Permalink to &quot;Local user state&quot;">​</a></h2><p>Treat project SQLite files as local user state. Tests should use temporary databases, not a real music-library database.</p>',15)])])}const m=a(d,[["render",o]]);export{u as __pageData,m as default};
